import { useMemo, useState, useEffect } from 'react';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces, cities, types } from '../data/spaces';
import SpaceCard from '../components/SpaceCard';
import MapView from '../components/MapView';
import Filters from '../components/Filters';

function useFavorites() {
  const [fav, setFav] = useState(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      return raw ? JSON.parse(raw) : [];
    } catch {
      return [];
    }
  });
  useEffect(() => {
    localStorage.setItem('wn:favorites', JSON.stringify(fav));
  }, [fav]);
  const toggle = (id) => setFav((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  return { favorites: fav, toggle };
}

export default function Search() {
  const [filterValues, setFilterValues] = useState({ city: '', type: '', minPrice: '', maxPrice: '' });
  const { favorites, toggle } = useFavorites();
  const [sortBy, setSortBy] = useState('relevance');
  const [showMap, setShowMap] = useState(false);
  const [homeCity, setHomeCity] = useState(() => {
    try {
      return localStorage.getItem('wn:homeCity') || '';
    } catch { return ''; }
  });
  useEffect(() => {
    localStorage.setItem('wn:homeCity', homeCity);
  }, [homeCity]);

  const filtered = useMemo(() => {
    let result = spaces.filter((s) => {
      if (filterValues.city && s.city !== filterValues.city) return false;
      if (filterValues.type && s.type !== filterValues.type) return false;
      if (filterValues.minPrice && s.pricePerDay < Number(filterValues.minPrice)) return false;
      if (filterValues.maxPrice && s.pricePerDay > Number(filterValues.maxPrice)) return false;
      return true;
    });
    if (sortBy === 'price-asc') result = [...result].sort((a, b) => a.pricePerDay - b.pricePerDay);
    if (sortBy === 'price-desc') result = [...result].sort((a, b) => b.pricePerDay - a.pricePerDay);
    if (sortBy === 'rating-desc') result = [...result].sort((a, b) => b.rating - a.rating);
    return result;
  }, [filterValues, sortBy]);

  const commuteFor = (s) => {
    if (!homeCity) return undefined;
    const same = s.city === homeCity;
    const min = same ? 15 : 45;
    const max = same ? 35 : 90;
    return Math.floor(Math.random() * (max - min + 1)) + min;
  };

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 w-full px-6 md:px-12 lg:px-16 py-10">
        <div className="flex items-center justify-between gap-4">
          <h2 className="text-2xl font-bold text-gray-900">Explore Workspaces</h2>
          <div className="flex items-center gap-3">
            <div className="text-sm text-gray-600 hidden md:block">{filtered.length} results</div>
            <select
              className="h-10 px-3 rounded-lg border border-gray-200 text-sm"
              value={homeCity}
              onChange={(e) => setHomeCity(e.target.value)}
            >
              <option value="">Commute from: Not set</option>
              {cities.map((c) => (
                <option key={c} value={c}>{c}</option>
              ))}
            </select>
            <select
              className="h-10 px-3 rounded-lg border border-gray-200 text-sm"
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
            >
              <option value="relevance">Sort: Relevance</option>
              <option value="price-asc">Price: Low to High</option>
              <option value="price-desc">Price: High to Low</option>
              <option value="rating-desc">Rating: High to Low</option>
            </select>
            <button
              className={`h-10 px-3 rounded-lg border text-sm ${showMap ? 'border-brand-600 text-brand-700 bg-brand-50' : 'border-gray-200 text-gray-700'}`}
              onClick={() => setShowMap(!showMap)}
            >
              {showMap ? 'List view' : 'Map view'}
            </button>
          </div>
        </div>

        <div className="mt-5 md:sticky md:top-20 z-10 bg-white/80 backdrop-blur supports-[backdrop-filter]:bg-white/60 rounded-2xl p-4 border border-gray-100">
          <Filters cities={cities} types={types} values={filterValues} onChange={setFilterValues} />
        </div>

        {!showMap ? (
          <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-6">
            {filtered.map((s) => (
              <SpaceCard key={s.id} space={s} onToggleFavorite={toggle} isFavorite={favorites.includes(s.id)} commuteMins={commuteFor(s)} />
            ))}
          </div>
        ) : (
          <div className="mt-6">
            <MapView spaces={filtered} />
          </div>
        )}
      </main>
      <Footer />
    </div>
  );
}
